Consider the following C-function in which a[] and b[] are two sorted integer arrays and c[n+m] be another integer array.

void xyz(int a[], int b[], int c[]) {
    int i, j, k;
    i = j = k = 0;
    while ((i < n) && (j < m))
        if (a[i] < b[j]) c[k++] = a[i++];
        else             c[k++] = b[j++];
}

Which of the following condition(s) hold(s) after the termination of the while loop?

  i.  j <= m, k = m + j - 1 and |a[n-1] - b[j]| <= a[i]  if i == n
  ii. i <= n, k = m + i - 1 and |b[m-1] - a[i]| <= b[j]  if j == m

A. only (i)
B. only (ii)
C. either (i) or (ii) but not both
D. neither (i) nor (ii)

Consider the program below:

#include <stdio.h>
int fun(int n, int *f_p) {
    int t, f;
    if (n <= 1) {
        *f_p = 1;
        return 1;
    }
    t = fun(n-1, f_p);
    f = t + *f_p;
    *f_p = t;
    return f;
}
int main() {
    int x = 15;
    printf("%d\n", fun(5, &x));
    return 0;
}

The value printed is:

A. 6
B. 8
C. 14
D. 15

What is the value printed by the following C program?

#include <stdio.h>
int f(int *a, int n) {
    if (n <= 0) return 0;
    else if (*a % 2 == 0) return *a + f(a+1, n-1);
    else return *a - f(a+1, n-1);
}
int main() {
    int a[] = {12, 7, 13, 4, 11, 6};
    printf("%d", f(a, 6));
    return 0;
}

A. -9
B. 5
C. 15
D. 19
